import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, pkg['id'])
                pkgs[key] = pkg.get('resolvedVersion', pkg.get('requestedVersion',''))
    return pkgs

b = extract(baseline)
a = extract(after)
allkeys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in allkeys:
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        changes.append((k[0], k[1], bv, av))
    else:
        unchanged.append((k[0], k[1], bv))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]:20s} {c[1]:40s} {c[2]:10s} -> {c[3]}')
print(f'\n=== UNCHANGED ({len(unchanged)} packages) ===')
for u in unchanged:
    print(f'{u[0]:20s} {u[1]:40s} {u[2]}')
"

